+import { analyzeRepository } from '@/services/ai.service';
+import type { RepositoryAnalysisRequest } from '@/types/ai';
+
+export async function POST(request: NextRequest) {
+  try {
+    // Parse request body
+    const body: RepositoryAnalysisRequest = await request.json();
+
+    // Validate required fields
+    if (!body.repositoryUrl || !body.repositoryName) {
+      return NextResponse.json(
+        {
+          error: 'Missing required fields: repositoryUrl and repositoryName',
+        },
+        { status: 400 }
+      );
+    }
+
+    // Call AI service
+    const analysis = await analyzeRepository(body);
+
+    // Return successful response
+    return NextResponse.json(analysis, { status: 200 });
+  } catch (error) {
+    console.error('Repository analysis API error:', error);
+
+    return NextResponse.json(
+      {
+        error: 'Failed to analyze repository',
+        details: error instanceof Error ? error.message : 'Unknown error',
+      },
+      { status: 500 }
+    );
+  }
+}
